import React, { useState } from 'react';
import Dashboard from './components/Dashboard'; 
import FileUploader from './components/FileUploader';
import { processCombinedData } from './utils/dataProcessor';

function App() {
  // Estado para guardar el resultado final procesado
  const [dashboardData, setDashboardData] = useState(null);

  // Esta función se dispara cuando FileUploader termina de leer AMBOS archivos
  const handleAllData = (csv, excel) => {
    try {
      // Pasamos los dos archivos al procesador que creamos antes
      const processed = processCombinedData(csv, excel);
      setDashboardData(processed);
    } catch (error) {
      console.error("Error al procesar los datos combinados:", error);
      alert("Error en el formato de los archivos. Verifique el Excel de Easy Docking.");
    }
  };

  return (
    <div className="bg-[#080c14] min-h-screen">
      {!dashboardData ? (
        // El nombre de la prop AQUÍ debe coincidir con el del componente FileUploader
        <FileUploader onAllDataLoaded={handleAllData} />
      ) : (
        <Dashboard data={dashboardData} />
      )}
    </div>
  );
}

export default App;
